import "../Project/Project.scss";
import Header from "../Header/Header";
import "bootstrap/dist/css/bootstrap.min.css";
import { Button } from "react-bootstrap";
import Emeka from "./../../assets/images/emekah3.jpg";
import { FiExternalLink } from "react-icons/fi";



const Project = (props) => {
  // const {
  //   title="",
  //   imageURL= "",
  //   desc="",
  //   techOne="",
  //   techTwo="",
  //   techThree="",
  //   techFour="",
  //   techFive="",
  //   techSix="",
  //   techSeven="",

  // } = props;
  return (
    <div className="row work__content">
      <div className="col-lg-6 work__first">
        <img src={props.imageURL} alt="Heyward" />
      </div>
      <div className="col-lg-6">
        <p className="text-green text-small">Featured Project</p>
        <div className="work__header">
          <h3>{props.title}</h3>
          <FiExternalLink className="work__header__ext-link" />
        </div>

        <p className="pt-4">
          {props.desc}
        </p>
        <div className="work__footer">
          <div className="text-green">
            <p>{props.techOne}</p>
          </div>
          <div className="text-green">
            <p>{props.techTwo}</p>
          </div>
          <div className="text-green">
            <p>{props.techThree}</p>
          </div>
          <div className="text-green">
            <p>{props.techFour}</p>
          </div>
          <div className="text-green">
            <p>{props.techFive}</p>
          </div>
          <div className="text-green">
            <p>{props.techSix}</p>
          </div>
          <div className="text-green">
            <p>{props.techSeven}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Project;
